const ALL_CARDIO = CARDIO_GROUPS.flatMap(g => g.options);
// Map any exercise (cardio or strength) to one of our custom category icons
// (see src/icons.jsx). Replaces the per-exercise emoji with a consistent,
// on-brand glyph. kind: "cardio" | "strength".
function exerciseCategory(ex, kind) {
  if (!ex) return kind === "strength" ? "dumbbell" : "run";
  // Custom exercises can carry a user-picked icon (S97b) — it always wins.
  if (ex.iconName) return ex.iconName;
  const s = `${ex.id || ""} ${ex.label || ""}`.toLowerCase();
  if (/\brest\b|rest day|rest_st/.test(s)) return "moon";
  if (/yoga|stretch|mobility|pilates|foam roll|cooldown|cool down|warm ?up/.test(s)) return "yoga";
  if (kind === "strength") {
    // Per-movement-pattern icons (S97g + S97i full set): every pattern reads at
    // a glance. Horizontal/Lower Push keep the barbell — bench + squats ARE the
    // classic barbell lifts, so it's semantic there, not a fallback.
    const c = (ex.cat || "").toLowerCase();
    if (/upper accessory/.test(c)) return "muscle";
    if (/lower accessory/.test(c)) return "legs";
    if (/carry/.test(c)) return "carry";
    if (/total body/.test(c)) return "bolt";
    if (/core/.test(c)) return "core";
    if (/vertical push/.test(c)) return "liftup";
    if (/vertical pull/.test(c)) return "pullup";
    if (/horizontal pull/.test(c)) return "pullrow";
    if (/lower pull/.test(c)) return "liftdown";
    return "dumbbell";
  }
  // Per-activity glyphs (S97b→S97f: standardized on Phosphor MIT icons).
  if (/swim|water/.test(s)) return "swim";
  if (/cycl|spin|bike/.test(s)) return "bike";
  if (/row|erg|ski/.test(s)) return "row";
  if (/stair|climb|ladder|versa/.test(s)) return "stairs";
  if (/kick|martial|wrestl|grappl|mma|karate|judo/.test(s)) return "kick";
  if (/box/.test(s)) return "boxing";
  if (/jump.?rope/.test(s)) return "jumprope";
  if (/hik|mountain/.test(s)) return "hike";
  if (/basketball|bball/.test(s)) return "basketball";
  if (/soccer/.test(s)) return "soccer";
  if (/tennis|pickle|badminton|squash/.test(s)) return "tennis";
  if (/volley/.test(s)) return "volleyball";
  if (/football|flag/.test(s)) return "football";
  if (/ping|table.?tennis/.test(s)) return "pingpong";
  if (/skat|rollerblad/.test(s)) return "skate";
  if (/danc|zumba/.test(s)) return "dance";
  if (/\bwalk\b|walking|walk_|_walk/.test(s)) return "walk";
  if (/jog|\brun\b|running|sprint|treadmill|ellipt/.test(s)) return "run";
  if (/hiit/.test(s)) return "flame";
  return "bolt"; // misc — energy
}
